// 2.8.1 | 2022-10-17 |raj |  STRY0127550 - Tech Debt - Task Types are used in code with hard coded values, modify to use a new value field in the table
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	g_scratchpad.numApprovalSubTasks = 0;

	var countSubtasks = new GlideAggregate('x_153465_discovert_route_task_instance');
	countSubtasks.addQuery('parent', current.sys_id);
	// STRY0127550 - change to use constants instead of hard coded values
	countSubtasks.addQuery('tasker_type.u_value', "IN",  
							TaskerTypes.CONST_TASKER_TYPE_APPROVAL_WITH_SIGNATURE + "," + 
							TaskerTypes.CONST_TASKER_TYPE_APPROVAL);
	countSubtasks.addAggregate('COUNT');
	countSubtasks.query();


	if(countSubtasks.next()){
		g_scratchpad.numApprovalSubTasks = countSubtasks.getAggregate('COUNT');
	}

})(current, previous);
